import { Vex } from 'vex-sdk';
import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const vex = new Vex({ apiKey: 'your-vex-key' });
const bedrock = new BedrockAgentRuntimeClient({ region: 'us-east-1' });

const command = new InvokeAgentCommand({
  agentId: 'your-agent-id',
  agentAliasId: 'your-alias-id',
  sessionId: 'candidate-session-123',
  inputText: 'Find top data scientists from knowledge base.'
});

const response = await bedrock.send(command);
const completion = response.completion;

// Verify KB retrieval diversity
const result = await vex.verify('kb-diversity-check', {
  input: command.inputText,
  output: completion,
  context: {
    domain: 'hr-recruitment',
    check: 'protected_class_representation',
    min_diversity_score: 0.8
  }
});

if (!result.passed) {
  console.log('Blocked:', result.issues);
} else {
  console.log('Approved:', completion);
}
